package cr.ac.ucr.mediacloud.controller;
import cr.ac.ucr.mediacloud.repository.UsuarioRepository;import jakarta.servlet.http.*;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.*;
@Controller public class AuthController{private final UsuarioRepository usuarios; public AuthController(UsuarioRepository usuarios){this.usuarios=usuarios;} @GetMapping("/") public String inicio(){return "redirect:/login";} @GetMapping("/login") public String login(){return "auth/login";} @PostMapping("/login") public String entrar(@RequestParam String correo,@RequestParam String clave,HttpSession s,Model m){return usuarios.login(correo,clave).map(u->{s.setAttribute("usuario",u);return "redirect:/dashboard";}).orElseGet(()->{m.addAttribute("error","Correo o contraseña incorrectos");return "auth/login";});} @PostMapping("/logout") public String salir(HttpSession s){s.invalidate();return "redirect:/login";} }
